// VoiceRecorder.tsx - full hold-to-talk implementation
import { useState, useRef, useCallback } from "react";

type VoiceState = "idle" | "listening" | "transcribing" | "thinking" | "speaking";

const STATE_LABEL: Record<VoiceState, string> = {
  idle: "Hold to speak",
  listening: "Listening...",
  transcribing: "Transcribing...",
  thinking: "Thinking...",
  speaking: "Speaking...",
};

export function VoiceRecorder({
  sessionId,
  onStateChange,
  onTranscript,
  onReply,
}: {
  sessionId: string;
  onStateChange: (s: VoiceState) => void;
  onTranscript: (t: string) => void;
  onReply: (r: string) => void;
}) {
  const [state, setState] = useState<VoiceState>("idle");
  const mrRef = useRef<MediaRecorder | null>(null);
  const chunksRef = useRef<Blob[]>([]);

  const update = (s: VoiceState) => { setState(s); onStateChange(s); };

  const startRecording = useCallback(async () => {
    if (state !== "idle") return;
    const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
    const mr = new MediaRecorder(stream, { mimeType: "audio/webm" });
    chunksRef.current = [];
    mr.ondataavailable = e => { if (e.data.size) chunksRef.current.push(e.data); };
    mr.onstop = async () => {
      stream.getTracks().forEach(t => t.stop());
      const blob = new Blob(chunksRef.current, { type: "audio/webm" });

      // Send for STT + Claude
      update("transcribing");
      const form = new FormData();
      form.append("audio", blob, "voice.webm");
      try {
        const res = await fetch(`/voice/${sessionId}/turn`, { method: "POST", body: form });
        const { transcript, reply } = await res.json();
        onTranscript(transcript);
        update("thinking");

        // TTS playback
        update("speaking");
        await playTTS(reply);
        onReply(reply);
      } catch (e) {
        console.error(e);
      } finally {
        update("idle");
      }
    };
    mr.start(200);   // collect chunks every 200ms
    mrRef.current = mr;
    update("listening");
  }, [state, sessionId]);

  const stopRecording = useCallback(() => {
    mrRef.current?.stop();
  }, []);

  return (
    <div className="flex flex-col items-center gap-3">
      <button
        onMouseDown={startRecording}
        onMouseUp={stopRecording}
        onTouchStart={startRecording}
        onTouchEnd={stopRecording}
        disabled={state !== "idle" && state !== "listening"}
        className={`w-16 h-16 rounded-full flex items-center justify-center text-2xl transition-all
          ${state === "idle"      ? "bg-indigo-600 hover:bg-indigo-500 shadow-lg" : ""}
          ${state === "listening" ? "bg-red-600 animate-pulse shadow-red-500/50 shadow-lg" : ""}
          ${["transcribing","thinking","speaking"].includes(state) ? "bg-slate-700 cursor-not-allowed" : ""}`}
      >
        {state === "listening" ? "..." : "mic"}
      </button>
      <span className="text-sm text-slate-400">{STATE_LABEL[state]}</span>
    </div>
  );
}

// playTTS.ts - stream and play TTS audio in the browser
export async function playTTS(text: string, voice = "alloy"): Promise<void> {
  const res = await fetch("/tts", {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify({ text, voice }),
  });
  if (!res.ok) throw new Error("TTS request failed");

  const audioCtx = new AudioContext();
  const reader = res.body!.getReader();
  const chunks: Uint8Array[] = [];

  // Collect entire MP3 stream
  while (true) {
    const { done, value } = await reader.read();
    if (done) break;
    if (value) chunks.push(value);
  }

  // Decode and play
  const total = chunks.reduce((n, c) => n + c.length, 0);
  const buf = new Uint8Array(total);
  let offset = 0;
  for (const c of chunks) { buf.set(c, offset); offset += c.length; }

  const decoded = await audioCtx.decodeAudioData(buf.buffer);
  const source = audioCtx.createBufferSource();
  source.buffer = decoded;
  source.connect(audioCtx.destination);

  return new Promise(resolve => {
    source.onended = () => { audioCtx.close(); resolve(); };
    source.start();
  });
}

