// Barge-in: allow user to interrupt while TTS is playing
// Arm a MediaRecorder while audio plays; if speech is detected, stop playback.

export function useBargIn(onInterrupt: () => void) {
  const analyserRef = useRef<AnalyserNode | null>(null);
  const rafRef = useRef<number | null>(null);

  const start = async () => {
    const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
    const ctx = new AudioContext();
    const src = ctx.createMediaStreamSource(stream);
    const analyser = ctx.createAnalyser();
    analyser.fftSize = 256;
    src.connect(analyser);
    analyserRef.current = analyser;
    const data = new Uint8Array(analyser.frequencyBinCount);

    const check = () => {
      analyser.getByteFrequencyData(data);
      const rms = Math.sqrt(data.reduce((s, v) => s + v * v, 0) / data.length);
      if (rms > 20) {   // threshold; tune per environment
        onInterrupt();
        stream.getTracks().forEach(t => t.stop());
        ctx.close();
        return;
      }
      rafRef.current = requestAnimationFrame(check);
    };
    rafRef.current = requestAnimationFrame(check);
  };

  const stop = () => {
    if (rafRef.current) cancelAnimationFrame(rafRef.current);
  };

  return { start, stop };
}
// Call useBargIn({ onInterrupt: () => audioRef.current?.pause() }) before TTS starts.
